'use strict';(function(){const indexCfg={cache:true};indexCfg.doc={id:'id',field:['title','content'],store:['title','href','section'],};const index=FlexSearch.create('balance',indexCfg);window.bookSearchIndex=index;index.add({'id':0,'href':'/docs/install/','title':"0 安装",'section':"Docs",'content':"安装 (45分钟)  下载并解压，链接 百度网盘 提取码：vbox 双击运行MapGIS 安装程序 Setup67.EXE  点击下一步  直到弹出如下界面 计算机名或者IP地址填入 127.0.0.1  双击运行虚拟狗 DogServer67.exe 右下角出现虚拟狗图标，点击确定  弹出三维绘制引擎选择 OpenGL 3D，确定  弹出如下界面，点击完成，安装成功。  桌面上双击如下图标，打开 MAPGIS67主菜单\n  "});index.add({'id':1,'href':'/docs/format_conversion/','title':"1 格式转换",'section':"Docs",'content':"第一节 格式转换（2学时） 影像格式转换（10分钟） 数据下载：链接 百度网盘 提取码：vbox    jpg、tif转msi\n 图像处理-图像分析 文件-数据输入    msi转jpg、tif\n 图像处理-图像分析 文件-数据输出    标准分幅栅格图像的校正 （20分钟） 标准分幅栅格图像的校正-DRG生产 （20分钟） DRG是Digital Raster Graphic的缩写，中文叫数字栅格地图：是根据现有纸质、胶片等地形图经扫描和几何纠正及色彩校正后，形成在内容、几何精度和色彩上与地形图保持一致的栅格数据集。\n小技巧：图例版的应用（10分钟）  栅格影像的裁剪（10分钟） 小技巧：可以用画图工具裁剪（10分钟）  "});index.add({'id':2,'href':'/docs/geometric_correction/','title':"3 校正图像",'section':"Docs",'content':"第一节 校正图像（2学时）  影像格式转换 影像几何校正 DRG生产（影像逐格网校正）  影像格式转换（10分钟） 数据下载：链接 百度网盘 提取码：vbox    jpg、tif转msi\n 图像处理-图像分析 文件-数据输入    msi转jpg、tif\n 图像处理-图像分析 文件-数据输出    标准分幅栅格图像的校正 （20分钟） 标准分幅栅格图像的校正-DRG生产 （20分钟） DRG是Digital Raster Graphic的缩写，中文叫数字栅格地图：是根据现有纸质、胶片等地形图经扫描和几何纠正及色彩校正后，形成在内容、几何精度和色彩上与地形图保持一致的栅格数据集。\n小技巧：图例版的应用（10分钟）  栅格影像的裁剪（10分钟） 小技巧：可以用画图工具裁剪（10分钟）  "});index.add({'id':3,'href':'/docs/generate_frame/','title':"4 生成图框",'section':"Docs",'content':"第?节 生成图框 "});index.add({'id':4,'href':'/docs/cut_image/','title':"4 剪裁图像",'section':"Docs",'content':"剪裁图像 "});index.add({'id':5,'href':'/docs/gen_wp/','title':"5 造区",'section':"Docs",'content':"实用服务 "});index.add({'id':6,'href':'/docs/image/','title':"图像处理分析",'section':"Docs",'content':"第一节 图像处理分析（2学时）  影像格式转换 影像几何校正 DRG生产（影像逐格网校正） 影像裁剪  影像格式转换（10分钟） 数据下载：链接 百度网盘 提取码：vbox    jpg、tif转msi\n 图像处理-图像分析 文件-数据输入    msi转jpg、tif\n 图像处理-图像分析 文件-数据输出    标准分幅栅格图像的校正 （20分钟） 标准分幅栅格图像的校正-DRG生产 （20分钟） DRG是Digital Raster Graphic的缩写，中文叫数字栅格地图：是根据现有纸质、胶片等地形图经扫描和几何纠正及色彩校正后，形成在内容、几何精度和色彩上与地形图保持一致的栅格数据集。\n小技巧：图例版的应用（10分钟）  栅格影像的裁剪（10分钟） 小技巧：可以用画图工具裁剪（10分钟）  "});index.add({'id':7,'href':'/docs/graphics/','title':"图形处理",'section':"Docs",'content':"图形处理 文件格式转换(5分钟)  图象处理-图象分析-文件-数据输入 选择文件格式-选择 jpg 格式文件-点击转换 对应目录生成 msi 格式文件  下载jpg 格式示例文件，转到百度网盘 提取码：vbox  点文件的输入1(10分钟)  设置工作目录 图形处理-输入编辑-新建工程 新建点文件、线文件、区文件 打开、关闭、编辑 点线区 文件 新建点、复制点、删除点、移动点 矩阵复制：点编辑-阵列复制点  如果工作目录不存在，新建的点文件将无法打开、编辑．  点文件的输入2(12分钟)  空心字 上下标  AL#-2#=O#-3   \\(Al_2O_3\\)   #+ 上标 #- 下标 #= 正常   分子式  /1/2000/  \\(\\frac1{2000}\\)     缩放技巧  F5 放大 F6 中间 F7 缩小    图形处理-输入编辑 1 工程及图层的建立 （10分钟）\n2 点文件的矢量化 （22分钟）\n选中图层，新增点\n3 线文件的矢量化 （10分钟）\n F8 加点 F9 减点  4 区文件的矢量化（10分钟）\n"});})();